#include <iostream>

using namespace std;

int main()
{
    cout << sizeof(int) << endl;
    cout << sizeof(char) << endl;
    cout << sizeof(double) << endl;

    return 0;
}

int arr[3] = {10, 20, 30};

// arr[0]'s address, arr[1]'s address, and arr[2]'s address
// are spaced exactly sizeof(int) bytes apart, back to back in memory

#include <iostream>

using namespace std;

int main()
{
    int arr[3] = {10, 20, 30};

    cout << (&arr[1] - &arr[0]) << endl;
    cout << (&arr[2] - &arr[0]) << endl;

    return 0;
}

